SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], Val([Quantity]) AS QuantityPurchased, Val([No_ of Pairs]) AS PairsPurchased, Val([av_ net unit cost])*Val([no_ of pairs]) AS ValuePurchased, [Purchase Line].[Currency Code], IIf([currency code]="USD",(Val([av_ net unit cost])*Val([no_ of pairs]))/[forms]![principale]![cambioeurodollaro],IIf(IsNull([currency code]) Or [currency code]="",(Val([av_ net unit cost])*Val([no_ of pairs])),"ERROR CURRENCY NOT AVAILABLE")) AS ValuePurchasedEur, Val([Purchase Line.Quantity Received]) AS QuantityReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueReceived, Val([Purchase Line.Quantity Invoiced]) AS QuantityInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueInvoicedPurchases
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])=""));

